import API from './axios';

export const registerUser = (data) =>
  API.post('/auth/register', data);

export const loginUser = (data) =>
  API.post('/auth/login', data);

export const dashboardLogin = (data) =>
  API.post('/auth/dashboard-login', data);

export const getMe = () =>
  API.get('/auth/me');
